var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"여러분, 우리 도시의 명물인 할로윈 코스튬 경연 대회도 어느새 막바지에 접어들었습니다!","JPN":"皆さん、わが都市の名物であるハロウィンコスチュームコンテストもいよいよ大詰めを迎えました。","ENG":"Ladies and gentlemen! We're finally in the last round of our city's world famous Halloween costume contest!","TWN":"各位，我們城市的特色，萬聖節扮裝大賽已接近尾聲了！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"쟁쟁한 경쟁자들 사이에서 살아남은 이들은 최후의 3인!","JPN":"錚々たる参加者の中で最後まで生き残ったのは3人！","ENG":"Three contenders remain after the fierce competition!","TWN":"一共有三位在眾多競爭對手中脫穎而出！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"과연 최후의 우승을 거머쥐는 자는 누구일까요?","JPN":"果たして優勝を勝ち取るのは誰でしょう？","ENG":"Who will become the final winner?","TWN":"冠軍將花落誰家呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헉! 헉! 아직 안 늦었죠?","JPN":"はあ、はあ！　まだ間に合いますよね？","ENG":"*Huff, huff* I'm not late, am I?","TWN":"呼！呼！我沒來晚吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"곧 결승이 시작될 거야. 잉그리드는?","JPN":"そろそろ決勝戦が始まるわ。イングリッドは？","ENG":"The final round is about to begin. Where's Ingrid?","TWN":"決賽快開始了，英格麗呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"가게엔 없던데요? 경연에 참가한 거 아니었어요?","JPN":"店にいなかったし、コンテストに参加してるんじゃないんですか？","ENG":"I didn't see her at the cafe. I thought she was participating in the contest.","TWN":"她不在店裡啊？她不是來參加大賽了嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그렇구나. 실은 우리도 막 도착한 참이었거든.","JPN":"そうなのね。実は私たちもここに着いたばかりなの。","ENG":"I see. Well, we just got here, too.","TWN":"是嗎？我們也是剛到。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라가 단 걸 좋아해서 노점상들을 뒤지느라......","JPN":"ラウラが甘いものが好きだから、露店でちょっと買い物してて……","ENG":"We had to hit up the street vendors to satisfy Laura's sweet tooth...","TWN":"蘿拉喜歡吃甜的，所以逛了下路邊攤……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"단 거요......?","JPN":"甘いもの……？","ENG":"Sweet tooth?","TWN":"甜的……？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"왜 그언 누느로 바라바? (왜 그런 눈으로 바라봐?)","JPN":"なぜそンなメでムる？　(なぜそんな目で見る？)","ENG":"Vy arf you shtawing at me vike vat? (Why are you staring at me like that?)","TWN":"幹嘛用那種眼神看我？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"사당 사느데 머 보대주 거 이서? (사탕 사는데 뭐 보태준 거 있어?)","JPN":"キャンデとかガーてくルダことヌいくスに。(キャンディとか買ってくれたことないくせに)","ENG":"Vot a vwoblem if I've vot a vweet tooth? (Got a problem if I've got a sweet tooth?)","TWN":"我吃糖有什麼不行的嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 아니에요!","JPN":"な、何でもないです！","ENG":"N-no!","TWN":"沒、沒有！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"부탁이니까 나중에 치과 가기 싫다고 땡깡 부리지만 마.","JPN":"お願いだから、あとで歯医者に行きたくないとワガママを言うのは勘弁して。","ENG":"Just don't throw a tantrum when you have to go to the dentist next time.","TWN":"拜託，以後可別嚷嚷著不去牙科了。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"오래 기다리셨습니다!","JPN":"お待たせしました。","ENG":"Thank you for your patience!","TWN":"各位，久等了！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"이제부터 결선 무대를 시작하겠습니다!","JPN":"ただ今より決勝戦を始めます！","ENG":"We will now begin the final round!","TWN":"決賽即將開始！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"첫 번째 후보는 지옥에서 기어 올라 온 천사! 신디 루퍼 양!","JPN":"一人目は地獄から這い上がってきた天使！　シンディ・ルーパーちゃん！","ENG":"Our first finalist is an angel from hell! Ms. Cindy Looper!","TWN":"第一位候選人是來自地獄的天使！辛蒂·洛珀！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_SAW","text":{"KOREA":"......천국에 계신 고용주님의 이름으로 이교도들의 축제를 즐기는 너희들을 용서한다.","JPN":"……天国にいる雇用主様の名にかけて、異教徒の祭りを楽しむあなたたちを許す。","ENG":"In the name of our Heavenly Employer, I forgive you heretics for celebrating this blasphemous festival.","TWN":"……我代表天國的主人饒恕樂享異教徒慶典的你們。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_SAW","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"하지만 이 녀석이 용서할까?!","JPN":"でも、こいつが許してくれるかな？","ENG":"But my little friend might beg to differ!","TWN":"但這個傢伙可不這麼想！！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_CUTSCEN_CHAINSAW_START"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"와아아아!!!","JPN":"わぁぁぁ！？!","ENG":"Woohoo!!!","TWN":"哇啊啊啊！！！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"멋져! 귀여워!","JPN":"素敵！　可愛い！","ENG":"Amazing! She's so adorable!","TWN":"好帥！好可愛！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 반응이 좋은 걸 보니 고생한 보람이 있네.","JPN":"ふふっ。いい反応ね。苦労した甲斐があったわ。","ENG":"Hah hah, it's so fulfilling to see everyone appreciate her costume so much.","TWN":"吼吼，看這個反應，感覺我的辛苦也沒白費啊。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"네 눈엔 저게 마녀가 입을 옷으로 보여?","JPN":"汝の目にはあれが魔女の衣装に見えるのか？","ENG":"Does that look like proper witch attire to you?","TWN":"妳覺得那個是魔女該穿的衣服嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아무리 봐도 슬래셔 무비에서 튀어 나온 것 같은 악당이잖아!","JPN":"どう見てもスプラッター映画に出て来そうな悪党じゃないか！","ENG":"She looks like the main villain from a slasher movie!","TWN":"這怎麼看都是血腥恐怖片裡的壞蛋吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머나. 방문객 본인도 깨닫지 못한 소망을 만족시켜 주는 게 베테랑 마녀의 실력 아닐까?","JPN":"あら。お客さん本人も気づいてない欲望を\\n満足させてあげることが、ベテラン魔女の仕事じゃないかしら？","ENG":"Come on. A true witch helps her clients realize their deepest desires, even if they're not aware of it.","TWN":"哎呀，滿足連客人自己都意識到的需求，不就是高手魔女的實力嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"물론 그 고리타분한 사고방식으로는 따라잡기 힘들겠지만, 후훗.","JPN":"もちろんその古い考え方じゃ\\nお客さんの気持ちを汲み取ることは難しいだろうけどね、ふふっ。","ENG":"Then again, I guess you're too old-fashioned to appreciate what that means. Hah hah.","TWN":"當然，妳那死腦筋是很難理解的，哼哼。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"등장부터 멋진 퍼포먼스 감사합니다, 신디 양!","JPN":"登場と同時に素敵なパフォーマンスを披露してくれました。ありがとう、シンディちゃん！","ENG":"Thank you for that grand performance, Ms. Looper!","TWN":"非常帥氣的登場啊，辛蒂小姐！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"그럼 계속해서 두 번째 후보를 만나 보죠!","JPN":"続いて二人目です！","ENG":"On to our next contestant!","TWN":"那我們接下來繼續看看第二位候選人！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"할로윈의 밤을 지배할 서큐버스의 여왕! 레지나 맥도날드 양!","JPN":"ハロウィンの夜を支配するサキュバスの女王！　レジーナ・マクドナルドちゃん！","ENG":"Presenting the succubus queen to reign over tonight! Ms. Regina McDonald!","TWN":"統治萬聖節之夜的魅魔女王！蕾佳娜·麥當勞！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"맥크레디 양 아니었어요?","JPN":"マクレディーちゃんでは？","ENG":"Wasn't her name MacCready?","TWN":"不就是麥克蕾蒂嗎？麥當勞？！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그러게. 사회자가 잘못 읽은 거 아닐까?","JPN":"だよね。司会者の言い間違いじゃない？","ENG":"I know. The emcee must have misread it.","TWN":"是不是主持人讀錯名字了？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"자! 여기 모인 관객 분들에게 우승을 향한 열망을 보여 주시죠!","JPN":"さあ！　ここにお集まりいただいた観客の皆さんに向けて\\n優勝への情熱を見せてください！","ENG":"Now! Please tell the audience how passionately you want to win!","TWN":"來！給觀眾們展現一下你的必勝決心吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"그, 그게...... 으음......","JPN":"えっ、えっと……ううん……","ENG":"W-well... Um...","TWN":"那、那個……嗯……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"다, 다들 좋은 할로윈 보내세요...... 하하, 하하하......","JPN":"み、皆さん、よいハロウィンをお過ごしください……はは、ははは……","ENG":"H-have a nice Halloween everyone... Hah hah... Hah hah hah...","TWN":"萬、萬聖節快樂……哈哈，哈哈哈……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CROWD_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"열심히 만든 작품이 실시간으로 침몰하고 있는데 무슨 할말 없어?","JPN":"頑張って作った服がリアルタイムで台無しに\\nなってるんだけど、何か言いたいことはない？","ENG":"How does it feel to watch your creation crash and burn right before your eyes?","TWN":"看到妳的作品快速落敗，妳就沒什麼話想說嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......흥. 원래 거장의 작품은 세상에 인정 받는 데 시간이 필요한 법이야.","JPN":"……ふん。昔から巨匠の作品は世間に認められるのに時間がかかるものだ。","ENG":"Hmpf! A true masterpiece always takes time to fully earn the world's recognition.","TWN":"……哼，大師的作品想被世人認可本就是需要時間的。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 그렇다고 해 둘게, 점장님.","JPN":"ふふっ、そういうことにしとくわね。店長。","ENG":"Sure, whatever you say, boss.","TWN":"哼哼，妳說是就是吧，店長。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아, 지금 울고 있는 거 아니지?","JPN":"あ、今泣いてるんじゃないわよね？","ENG":"You're not crying now, are you?","TWN":"喂，妳不會是要哭了吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"하하, 첫 번째 후보보다는 박력이 떨어지네요.","JPN":"はは、一人目より迫力に欠けますね。","ENG":"Hah hah, I guess she's feeling a bit shy compared to our first contestant.","TWN":"哈哈，貌似比第一位候選人差了那麼點魄力啊。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"응? 잠시만요. 레지나 양에게 전화 연결이 들어 왔군요.","JPN":"ん？　お待ちください。レジーナちゃんに入電です。","ENG":"Huh? Hang on. We've got an incoming call for Ms. McDonald.","TWN":"嗯？等等，有人要在現場連線蕾佳娜小姐。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"저, 저 말인가요?","JPN":"わ、私ですか？","ENG":"F-for me?","TWN":"我，我嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"누구시죠......?","JPN":"どなたでしょう……？","ENG":"Who could be calling me?","TWN":"請問是哪位……？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대체 뭔가요, 군중 앞에서 참새처럼 떠는 그 한심한 꼬락서니는?","JPN":"いったいどういうことですの？　群衆の前で小鳥みたいに震えるその情けない姿は！","ENG":"Why are you trembling like a pathetic sparrow in front of the crowd?","TWN":"妳現在在幹什麼？在大眾面前做這麼丟臉的行為。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"패, 팬드래건 양?! 어디서 보고 있는 거죠?!","JPN":"ペンドラゴンさん？　どこから見ているのですか？","ENG":"M-Miss Pendragon? Where are you right now?","TWN":"潘、潘德拉貢？！妳怎麼知道的？！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"TV 생방송으로 시청 중이랍니다.","JPN":"テレビの生放送を見ています。","ENG":"I'm watching you live on television.","TWN":"我正在看現場直播。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관의 숙적에 대한 정보 수집도 제겐 중요한 일과이기 때문이죠.","JPN":"機関の宿敵に対する情報収集も私には大事な日課ですわ。","ENG":"Gathering intelligence on our agency's mortal enemy is a vital part of my daily routine.","TWN":"因為對我來說收集敵對機關的情報也是很重要的。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"찾았다, 홍차 폭탄!","JPN":"見つけた！　紅茶爆弾！","ENG":"There you are, Tea Bomb!","TWN":"找到了，紅茶炸彈！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"라이언 영감이 너 또 서류 결재는 안하고 하루 종일 TV만 본다고...... ","JPN":"お前がまた書類決裁をサボって一日中テレビばっか見てるってライアンのジジイが…… ","ENG":"That old chap Ryan said you'd be watching the telly all day instead of signing off the documents— ","TWN":"瑞安老頭子又要說妳不好好工作整天在看電視了……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"컥!","JPN":"げっ！","ENG":"Ack!","TWN":"咦！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_HIT_STING_BIG"},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 지금 당신의 추태는 뭔가요?","JPN":"ところで、今のあなたの無様な姿は何ですか？","ENG":"Now, how do you explain this horrendous presentation?","TWN":"不過，妳怎麼這麼一副醜態？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서야 제 라이벌로서 당당히 나설 수 있겠나요?","JPN":"その程度で私のライバルだと堂々と言えるのですか？","ENG":"Can you truly declare yourself as my worthy rival like this?","TWN":"妳這樣怎麼成為我堂堂正正的對手？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"하, 하지만 이렇게 많은 사람들 앞에서는 부끄러워서......","JPN":"し、しかし、こんなに大勢の前では恥ずかしくて……","ENG":"B-but in front of an audience this large... I have stage fright...","TWN":"可、可是，這麼多人看著，我有點不好意思……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"쓸데없는 내숭은 그만두세요.","JPN":"余計な猫かぶりはやめなさい。","ENG":"Oh, poppycock.","TWN":"妳別裝了。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신은 사악하기로는 둘째 가라면 서러울 고대 가문의 후계자입니다.","JPN":"あなたはこの世で一番邪悪な古代名家の後継者なのです。","ENG":"You are the heir to an ancient family whose villainy is second to none.","TWN":"妳忘了妳是古代邪惡家族的繼承人嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 자기 혈통에 맞게, 지금 느끼는 수치심을 분노로 바꾸어 터뜨리세요.","JPN":"なので、自分の血統に相応しく、今感じてる羞恥心を怒りに変えてぶつけてください。","ENG":"Turn that shame into wrath, as would befit your nefarious bloodline.","TWN":"不要忘記妳的血統，把現在感受到的羞恥心轉化為憤怒爆發出來。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"수치심을 분노로......?","JPN":"羞恥心を怒りに……？","ENG":"Turn the shame into wrath?","TWN":"將羞恥心轉化為憤怒……？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래요. 그리고 그 분노를 지금 당신이 가장 증오하는 자에게 겨누는 거죠.","JPN":"そうです。そして、その怒りを今あなたが一番憎んでいる者に向けるのです。","ENG":"Quite right. And direct that wrath unto whom you despise the most.","TWN":"是的，然後把憤怒對準妳最憎惡的人。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"자신의 감정 하나 제대로 통제하지 못한다면, 제 티타임에 초대 받을 기회는 영영 없을 겁니다.","JPN":"自分の感情すらコントロールできないのなら\\n私のティータイムに招待されるチャンスは永遠にないでしょう。","ENG":"If you cannot control your own emotions, you'll hardly have the opportunity to receive an invitation to tea time.","TWN":"如果妳連妳自己的感情都控制不好，妳將永遠沒有資格參加我的茶會。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 기대하고 있겠어요.","JPN":"それでは期待しています。","ENG":"Right, then. I'll be looking forward to a jolly good performance.","TWN":"期待妳的表現。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"지금 내가 가장 증오하는 사람......","JPN":"今、私が一番憎んでいる人……","ENG":"The person I despise the most right now...","TWN":"現在我最憎惡的人……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"리벳......","JPN":"リベット……","ENG":"Rivet...","TWN":"里維……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"처음 만났을 때도 그러더니 이번에도 또......","JPN":"初めて会った時もそうだったけど、今回もまた……","ENG":"She did this to me the first time we met... and yet again...","TWN":"第一次見面的時候就是如此，沒想到現在又……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"네? 잘 안 들리는데요. 뭐라고 하셨죠?","JPN":"はい？　聞き取れませんでした。今、何か言いましたか？","ENG":"Pardon, ma'am? What did you say?","TWN":"嗯？妳說什麼？聽不太清楚。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"그 천한 것이...... 저한테 이런 굴욕을 맛보게 하고도 무사할 줄 알았던 건가요......?","JPN":"あの下品な者が……\\n私にこんな屈辱を味わわせてただで済むとでも思ったの……？","ENG":"You wretched pleb... Did you truly think you'd live to see another day after subjecting me to such shame?","TWN":"卑鄙無恥……讓我感受到如此屈辱，以為自己能平安無事嗎……？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"좋아요. 살을 에는 혹한 속에서도 마음 편히 잠들 수 있을지......","JPN":"いいでしょう。身を切るような酷寒の中でも安らかに眠れるのか……","ENG":"Very well... Let us see if you will rest easy despite the gut-wrenching cold...","TWN":"好，我就看著你如何在刻骨的酷寒中安穩入眠……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"그 알량한 재주로 영원토록 이어질 악몽 속에서 살아남을 수 있을지......!","JPN":"そのつまらない技で永遠に続く悪夢から生き残れるのか……！","ENG":"We shall see if your trivial tricks will let you survive this eternal nightmare!","TWN":"用你弱小的能力能否在接連不斷的惡夢存活呢……！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"오늘 밤 당신의 꿈 속에서 확인하러 가기로 하죠!","JPN":"今晩、それを確かめるためにあなたの夢にお邪魔しますわ！","ENG":"I shall visit you personally in your dream tonight!","TWN":"今晚，我將出現在你的夢中！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"오! 호호호호호!","JPN":"おほほほほほ！","ENG":"Ah hah hah hah hah!","TWN":"哇！哈哈哈哈哈！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"와아아!! 멋져요!","JPN":"わああ！？　素敵！","ENG":"Wow! That's awesome!","TWN":"哇啊啊！！好帥啊！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"언니! 제 꿈에도 나와 주세요!!","JPN":"お姉ちゃん！　私の夢にも出てきてほしい！！","ENG":"Please come visit me in my dreams, too!","TWN":"姐姐！也出現在我的夢裡吧！！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"과연! 마지막 순간에 우승을 향한 열정을 폭발시켜 주신 밤의 여왕!","JPN":"さすがですね！　最後に優勝への情熱を見事に爆発させた夜の女王！","ENG":"Oh my soul! The night queen has shown us her true game at the very last minute!","TWN":"向我們展示了奪冠信心的夜之女王！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"레지나 맥도날드 양의 무대였습니다!","JPN":"レジーナ・マクドナルドちゃんの舞台でした！","ENG":"A round of applause for Ms. Regina McDonald!","TWN":"蕾佳娜·麥當勞小姐的表演結束了！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"그럼 이제 마지막 결선 후보를 만나 보겠습니다!","JPN":"さあ、いよいよ最後の候補者です！","ENG":"Now, then. Time to meet our final contestant!","TWN":"接下來，我們有請最後一位候選人！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"아무리 할로윈이라도 제멋대로 구는 악령들은 큰 코 다치기 마련!","JPN":"いくらハロウィンでもわがままに振舞う悪霊たちは痛い目にあうべし！","ENG":"Those mischievous ghosts better behave themselves this Halloween!","TWN":"即使是萬聖節，也不能讓惡靈縱橫！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"유령 사냥꾼이 나타났습니다! 카페 스트레가의 잉그리드 요하나 양!","JPN":"幽霊狩人のご登場です！　カフェストレガのイングリッド・ヨハンナちゃん！","ENG":"For we have here a mighty ghost hunter! Ms. Ingrid Johanna of Cafe Strega!","TWN":"我們的幽靈獵人出現了！史特雷加咖啡店的英格麗小姐！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};